BEGIN
  FOR item IN SELECT * FROM jsonb_to_recordset(catalog) AS x(
    name text, description text, category text, preview_url text, price_coins integer, rarity text, effect_type text, effect_value text, effect_payload jsonb
  ) LOOP
    IF NOT EXISTS (
      SELECT 1 FROM public.store_items
      WHERE effect_type = item.effect_type
        AND COALESCE(effect_value, '') = COALESCE(item.effect_value, '')
        AND name = item.name
    ) THEN
      INSERT INTO public.store_items(name, description, category, preview_url, price_coins, rarity, effect_type, effect_value, effect_payload)
      VALUES (item.name, item.description, item.category, item.preview_url, item.price_coins, item.rarity, item.effect_type, item.effect_value, item.effect_payload);
    END IF;
  END LOOP;
END $$;

SELECT 'NightGram market cosmetic catalog seeded' AS status;
